interface ExtractedData {
  summary: string;
  keyPoints: string[];
  sentiment: "positive" | "neutral" | "negative";
}

async function analyzeDocument(fileBuffer: Buffer): Promise<ExtractedData> {
  // Step 1: Extract text from the PDF (CPU-bound, but async in Node)
  const rawText = await extractPDFText(fileBuffer);

  // Step 2: Run multiple AI analysis tasks in parallel
  const [summary, keyPoints, sentiment] = await Promise.all([
    withRetry(() => summarizeText(rawText)),
    withRetry(() => extractKeyPoints(rawText)),
    withRetry(() => analyzeSentiment(rawText)),
  ]);

  const result: ExtractedData = { summary, keyPoints, sentiment };

  // Step 3: Persist results (fire-and-forget — we don't await this)
  saveToDatabase(result).catch((err) => {
    console.error("DB save failed, will retry later:", err);
    queueForRetry(result);
  });

  return result;
}

